import React, { useState } from 'react';
import { login } from '../services/auth_service';

const Login = ({ onLoginSuccess }) => {
    const [selectedRole, setSelectedRole] = useState('admin');
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');

    // Demo credentials for each role
    const roleCredentials = {
        admin: { email: 'admin@resora.com', password: '12345678' },
        teacher: { email: 'hina.i@university.edu', password: '12345678' },
        ta: { email: 'ta.sana@nu.edu.pk', password: '12345678' },
        student: { email: '24l0601@lhr.nu.edu.pk', password: '12345678' }
    };

    const roles = [
        { id: 'admin', name: 'Admin', description: 'Full system access', icon: '⬡', color: '#8b5cf6' },
        { id: 'teacher', name: 'Teacher', description: 'Faculty portal', icon: '👨‍🏫', color: '#3b82f6' },
        { id: 'ta', name: 'Teaching Assistant', description: 'TA portal', icon: '🧑‍🏫', color: '#f59e0b' },
        { id: 'student', name: 'Student', description: 'Student portal', icon: '🎓', color: '#10b981' }
    ];

    const handleRoleSelect = (roleId) => {
        setSelectedRole(roleId);
        const creds = roleCredentials[roleId];
        setEmail(creds.email);
        setPassword(creds.password);
        setError('');
    };

    const handleSubmit = async (e) => {
        e.preventDefault();

        if (!email || !password) {
            setError('Please enter both email and password');
            return;
        }

        setLoading(true);
        setError('');

        const result = await login(email, password);

        if (result.success) {
            onLoginSuccess(result.user);
        } else {
            setError(result.message);
        }

        setLoading(false);
    };

    return (
        <div className="login-container">
            <div className="login-card">
                {/* Left Side - Branding */}
                <div className="login-brand">
                    <div className="logo">
                        <span className="logo-icon">🏛️</span>
                        <span className="logo-text">SCRAS</span>
                    </div>
                    <h1>Campus Resource<br />Allocation System</h1>
                    <p className="brand-description">
                        Streamline your campus operations with intelligent scheduling,
                        room management, and resource allocation.
                    </p>
                    <div className="features">
                        <div className="feature">✓ Multi-department management</div>
                        <div className="feature">✓ Automated timetable generation</div>
                        <div className="feature">✓ Role-based access control</div>
                        <div className="feature">✓ Real-time room booking</div>
                    </div>
                </div>

                {/* Right Side - Login Form */}
                <div className="login-form-container">
                    <div className="form-wrapper">
                        <h2>Sign in to your portal</h2>
                        <p className="form-subtitle">Select your role and enter your credentials</p>

                        {/* Role Selection Buttons */}
                        <div className="role-selector">
                            {roles.map(role => (
                                <button
                                    key={role.id}
                                    className={`role-btn ${selectedRole === role.id ? 'active' : ''}`}
                                    onClick={() => handleRoleSelect(role.id)}
                                    style={{
                                        borderColor: selectedRole === role.id ? role.color : '#e2e8f0',
                                        backgroundColor: selectedRole === role.id ? `${role.color}10` : 'white'
                                    }}
                                >
                                    <span className="role-icon">{role.icon}</span>
                                    <div className="role-info">
                                        <strong>{role.name}</strong>
                                        <span>{role.description}</span>
                                    </div>
                                </button>
                            ))}
                        </div>

                        {/* Login Form */}
                        <form onSubmit={handleSubmit}>
                            <div className="input-group">
                                <label>Email</label>
                                <input
                                    type="email"
                                    value={email}
                                    onChange={(e) => setEmail(e.target.value)}
                                    placeholder="Enter your email"
                                    disabled={loading}
                                />
                            </div>

                            <div className="input-group">
                                <label>Password</label>
                                <input
                                    type="password"
                                    value={password}
                                    onChange={(e) => setPassword(e.target.value)}
                                    placeholder="Enter your password"
                                    disabled={loading}
                                />
                            </div>

                            {error && <div className="error-message">{error}</div>}

                            <button type="submit" className="continue-btn" disabled={loading}>
                                {loading ? 'Signing in...' : `Continue to ${selectedRole === 'admin' ? 'Admin' : selectedRole === 'teacher' ? 'Teacher' : selectedRole === 'ta' ? 'TA' : 'Student'} Portal →`}
                            </button>
                        </form>

                        <div className="login-footer">
                            <span>Protected by SCRAS Auth · Encrypted</span>
                            <div className="status-indicator">
                                <span className="dot"></span> All systems operational
                            </div>
                        </div>
                    </div>
                </div>
            </div>
            <div className="copyright">
                © 2026 SCRAS Platform. v2.1.0
            </div>
        </div>
    );
};

export default Login;
